FLAGS = {
    "dark_mode": True,
    "beta_features": False,
    "new_dashboard": True,
    "analytics_v2": False,
}


def _to_snake_case(flag_name):
    """Convert a camelCase or snake_case flag name to snake_case."""
    normalized = []
    for character in flag_name:
        if character.isupper():
            normalized.append("_")
            normalized.append(character.lower())
        else:
            normalized.append(character)
